import React, { useEffect, useState } from "react";
import { useSearchParams } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { resetPassword } from "../../features/ResetPassword/ResetPasswordSlice";
import { useNavigate } from "react-router-dom";
import { useFormik } from "formik";
import * as Yup from "yup";

const ResetPassword = () => {
  const [searchParams] = useSearchParams();
  const token = searchParams.get("token");

  const dispatch = useDispatch();
  const navigate = useNavigate();

  const { loading, successMessage, errorMessage } = useSelector(
    (state) => state.resetPassword
  );

  const [error, setError] = useState("");

  const validationSchema = Yup.object({
    currentPassword: Yup.string().required("Current password is required"),
    newPassword: Yup.string().required("New password is required"),
    confirmPassword: Yup.string()
      .oneOf([Yup.ref("newPassword"), null], "Passwords must match")
      .required("Confirm password is required"),
  });

  const formik = useFormik({
    initialValues: {
      currentPassword: "",
      newPassword: "",
      confirmPassword: "",
    },
    validationSchema,
    onSubmit: (values) => {
      dispatch(resetPassword({ token, currentPassword: values.currentPassword, newPassword: values.newPassword }));
    },
  });

  useEffect(() => {
    if (successMessage) {
      setTimeout(() => {
        navigate("/PasswordChangeSuccessPage");
      }, 2000);
    }
  }, [successMessage, navigate]);

  useEffect(() => {
    if (errorMessage) {
      // Check if errorMessage is an object and extract the message if it is
      if (typeof errorMessage === "object" && errorMessage.message) {
        setError(errorMessage.message);
      } else {
        setError(errorMessage);
      }
    }
  }, [errorMessage]);

  return (
    <div className="flex justify-center items-center min-h-screen bg-gray-900 py-6 px-4">
      <div className="max-w-md  bg-white p-8 rounded-xl shadow-lg border-2 border-gray-300 h-[500px] w-[800px]">
        <h2 className="text-3xl font-bold text-center text-gray-700 mb-6">Reset Password</h2>
        <form onSubmit={formik.handleSubmit} className="space-y-6 h-full overflow-auto">
          {/* Current Password */}
          <div className="mb-4">
            <label htmlFor="currentPassword" className="block text-sm font-medium text-gray-600 mb-2">
              Current Password
            </label>
            <input
              id="currentPassword"
              type="password"
              placeholder="Enter current password"
              {...formik.getFieldProps("currentPassword")}
              className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            {formik.touched.currentPassword && formik.errors.currentPassword && (
              <p className="text-red-500 text-sm">{formik.errors.currentPassword}</p>
            )}
          </div>

          {/* New Password */}
          <div className="mb-4">
            <label htmlFor="newPassword" className="block text-sm font-medium text-gray-600 mb-2">
              New Password
            </label>
            <input
              id="newPassword"
              type="password"
              placeholder="Enter new password"
              {...formik.getFieldProps("newPassword")}
              className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            {formik.touched.newPassword && formik.errors.newPassword && (
              <p className="text-red-500 text-sm">{formik.errors.newPassword}</p>
            )}
          </div>

          {/* Confirm New Password */}
          <div className="mb-4">
            <label htmlFor="confirmPassword" className="block text-sm font-medium text-gray-600 mb-2">
              Confirm New Password
            </label>
            <input
              id="confirmPassword"
              type="password"
              placeholder="Confirm new password"
              {...formik.getFieldProps("confirmPassword")}
              className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            {formik.touched.confirmPassword && formik.errors.confirmPassword && (
              <p className="text-red-500 text-sm">{formik.errors.confirmPassword}</p>
            )}
          </div>

          {/* Submit Button */}
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-blue-600 text-white py-2 px-4 rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-400"
          >
            {loading ? "Resetting..." : "Reset Password"}
          </button>

          {/* Show error message */}
          {error && <p className="text-red-500 text-center mt-4">{typeof error === "string" ? error : error?.message || String(error)}</p>}

          {/* Show loading message */}
          {loading && <p className="text-center text-gray-600 mt-4">Loading...</p>}
        </form>
      </div>
    </div>
  );
};

export default ResetPassword;
